              {/* SALDO FINAL */}
              <tr className="bg-slate-900 text-white font-black text-[11px] shadow-lg">
                <td className="p-5 sticky left-0 bg-slate-900 z-10 uppercase tracking-[0.2em] border-r border-slate-800">Saldo Operacional (=)</td>
